const item = $input.first().json;

// O n8n às vezes entrega a resposta do HTTP Request como objeto,
// e às vezes como array com um objeto dentro.
const data = Array.isArray(item) ? item[0] : item;

const responseText =
  data?.candidates?.[0]?.content?.parts
    ?.map(part => part.text ?? '')
    .join('\n')
    .trim();

const fallback =
  'Olá! Sou o SorrisoBot AI da Clínica Sorriso Vivo. Recebi sua mensagem e vou te ajudar. Você deseja agendar uma consulta, tirar uma dúvida ou solicitar um orçamento?';

return [
  {
    json: {
      responseText: responseText || fallback,
      generatedAt: new Date().toISOString(),
      model: data?.modelVersion ?? 'gemini-2.5-flash',
      responseId: data?.responseId ?? null,
      usageMetadata: data?.usageMetadata ?? null
    }
  }
];

const normalized = $('Normalize Evolution Payload').first().json;
const ai = $('Extract Gemini Response').first().json;

return [
  {
    json: {
      number: normalized.phoneRaw,
      text: ai.responseText,
      linkPreview: false
    }
  }
];

const conversation = $('Supabase - Get Or Create Conversation').first().json;
const contact = $('Supabase - Upsert Contact').first().json;
const ai = $('Extract Gemini Response').first().json;
const evolutionResponse = $('Evolution API - Send WhatsApp Message').first().json;
const normalized = $('Normalize Evolution Payload').first().json;

return [
  {
    json: {
      conversation_id: conversation.id,
      contact_id: contact.id,
      direction: 'outbound',
      type: 'text',
      intent: 'desconhecida',
      sentiment: 'neutro',
      provider: 'gemini_evolution_api',
      provider_message_id:
        evolutionResponse?.key?.id ??
        evolutionResponse?.messageId ??
        evolutionResponse?.id ??
        null,
      content: ai.responseText,
      ai_model: 'gemini-2.5-flash',
      raw_payload: evolutionResponse,
      metadata: {
        sent_by: 'n8n',
        instance: normalized.instance,
        remote_jid: normalized.remoteJid
      }
    }
  }
];

const conversation = $('Supabase - Get Or Create Conversation').first().json;

return [
  {
    json: {
      conversation_id: conversation.id,
      event_type: 'agent_response_sent',
      description: 'Resposta automática enviada pelo SorrisoBot AI via Evolution API.',
      metadata: {
        workflow: 'SorrisoBot AI - WhatsApp Agent v1',
        model: 'gemini-2.5-flash',
        source: 'n8n'
      }
    }
  }
];

const item = $input.first().json;

const rawText =
  item.messageText ||
  item.content ||
  item.text ||
  item.message ||
  item.body ||
  item.transcription ||
  '';

const text = String(rawText)
  .toLowerCase()
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .trim();

function hasAny(words) {
  return words.some((word) => text.includes(word));
}

let intent = 'unknown';
let confidence = 0.4;
let status = 'active';
let shouldUseGemini = true;
let shouldHandoff = false;
let aiPaused = false;
let staticReply = null;
let handoffReason = null;

if (!text) {
  intent = 'unknown';
  confidence = 0.1;
}

else if (
  hasAny([
    'atendente',
    'humano',
    'pessoa',
    'recepcao',
    'recepcionista',
    'falar com alguem',
    'quero falar com alguem',
    'me chama no atendimento',
    'suporte'
  ])
) {
  intent = 'human_handoff';
  confidence = 0.95;
  status = 'waiting_human';
  shouldUseGemini = false;
  shouldHandoff = true;
  aiPaused = true;
  handoffReason = 'patient_requested_human';
  staticReply = 'Claro! Vou encaminhar sua conversa para um atendente da Clínica Sorriso Vivo. Por favor, aguarde um momento.';
}

else if (
  hasAny([
    'dor forte',
    'muita dor',
    'sangrando',
    'sangramento',
    'inchado',
    'inchaço',
    'trauma',
    'bati o dente',
    'quebrei o dente',
    'dente quebrou',
    'urgencia',
    'urgente',
    'emergencia',
    'emergência'
  ])
) {
  intent = 'emergency';
  confidence = 0.95;
  status = 'waiting_human';
  shouldUseGemini = false;
  shouldHandoff = true;
  aiPaused = true;
  handoffReason = 'possible_dental_emergency';
  staticReply = 'Entendi. Como pode ser uma urgência odontológica, vou encaminhar sua conversa para um atendente da Clínica Sorriso Vivo. Se houver sangramento intenso, trauma grave ou dor insuportável, procure atendimento de urgência imediatamente.';
}

else if (
  hasAny([
    'agendar',
    'marcar',
    'marca',
    'consulta',
    'gostaria de marcar',
    'quero marcar',
    'quero agendar',
    'horario',
    'horário',
    'tem vaga',
    'disponibilidade',
    'posso marcar'
  ])
) {
  intent = 'appointment_request';
  confidence = 0.9;
  status = 'active';
}

else if (
  hasAny([
    'remarcar',
    'mudar horario',
    'mudar horário',
    'trocar horario',
    'trocar horário',
    'alterar consulta'
  ])
) {
  intent = 'reschedule_request';
  confidence = 0.9;
  status = 'active';
}

else if (
  hasAny([
    'cancelar',
    'desmarcar',
    'cancelamento',
    'nao vou conseguir ir',
    'não vou conseguir ir'
  ])
) {
  intent = 'cancel_request';
  confidence = 0.9;
  status = 'active';
}

else if (
  hasAny([
    'preco',
    'preço',
    'valor',
    'quanto custa',
    'tabela',
    'orcamento',
    'orçamento',
    'forma de pagamento',
    'parcelam',
    'parcela'
  ])
) {
  intent = 'price_question';
  confidence = 0.85;
  status = 'active';
}

else if (
  hasAny([
    'horario de atendimento',
    'horário de atendimento',
    'que horas abre',
    'que horas fecha',
    'funciona hoje',
    'abre hoje',
    'atende sabado',
    'atende sábado'
  ])
) {
  intent = 'clinic_hours';
  confidence = 0.85;
  status = 'active';
}

else if (
  hasAny([
    'endereco',
    'endereço',
    'localizacao',
    'localização',
    'onde fica',
    'como chegar',
    'mapa'
  ])
) {
  intent = 'location_question';
  confidence = 0.85;
  status = 'active';
}

else if (
  hasAny([
    'clareamento',
    'limpeza',
    'canal',
    'implante',
    'aparelho',
    'ortodontia',
    'extracao',
    'extração',
    'restauracao',
    'restauração',
    'avaliacao',
    'avaliação',
    'procedimento'
  ])
) {
  intent = 'procedure_question';
  confidence = 0.8;
  status = 'active';
}

else if (
  hasAny([
    'oi',
    'ola',
    'olá',
    'bom dia',
    'boa tarde',
    'boa noite'
  ])
) {
  intent = 'greeting';
  confidence = 0.75;
  status = 'active';
}

else if (
  hasAny([
    'obrigado',
    'obrigada',
    'valeu',
    'agradeço',
    'agradeco'
  ])
) {
  intent = 'thanks';
  confidence = 0.75;
  status = 'active';
}

return [
  {
    json: {
      ...item,
      intent,
      intentConfidence: confidence,
      conversationStatus: status,
      shouldUseGemini,
      shouldHandoff,
      aiPaused,
      aiPausedReason: handoffReason,
      staticReply,
      detectedAt: new Date().toISOString()
    }
  }
];
